                "filter",
                "Use Tera 2 list comprehension instead.",
            );
            let attribute = args.must_get::<&str>("attribute")?;
            let expected = args.get::<Value>("value")?;
            Ok(Value::from(
                arr.iter()
                    .filter(|v| {
                        let Some(actual) = v.get_from_path(attribute) else {
                            return false;
                        };
                        match &expected {
                            Some(expected) => actual == expected,
